import ipaddress

def validate_ip(address: str) -> dict:
    try:
        clean = address.split('/')[0]
        ip = ipaddress.ip_address(clean)
        if ip.is_loopback:
            ip_type = 'loopback'
        elif ip.is_multicast:
            ip_type = 'multicast'
        elif ip.is_link_local:
            ip_type = 'link-local'
        elif ip.is_private:
            ip_type = 'private'
        else:
            ip_type = 'public'
        binary = ''.join(format(int(o), '08b') for o in clean.split('.')) if ip.version == 4 else ''
        return {'valid': True, 'version': ip.version, 'type': ip_type, 'binary': binary}
    except ValueError:
        return {'valid': False, 'version': 0, 'type': 'invalid', 'binary': ''}

def is_same_subnet(ip1: str, ip2: str, mask: str) -> bool:
    try:
        prefix = int(mask) if mask.isdigit() else sum(bin(int(x)).count('1') for x in mask.split('.'))
        net1 = ipaddress.ip_network(f'{ip1}/{prefix}', strict=False)
        net2 = ipaddress.ip_network(f'{ip2}/{prefix}', strict=False)
        return net1 == net2
    except ValueError:
        return False
